    old_nullifier_hash: bytesToHex(oldNullifierHashBytes),
    old_recipient_commitment: bytesToHex(oldRecipientCommitBytes),
    old_r_leaf: bytesToHex(oldRLeafBytes),
    old_bind_hash: bytesToHex(oldBindHashBytes),
